1	// pv24t — P-code Trace Interpreter for COR24
2	//
3	// Reads a .p24 binary and executes it with optional instruction-level tracing.
4	// Semantics match pvm.s exactly: dual-stack architecture, 24-bit word size,
5	// signed arithmetic, same frame layout, same trap behavior.
6	//
7	// Usage:
8	//   pv24t <file.p24>              # Run, program output to stdout
9	//   pv24t -t <file.p24>           # Run with trace to stderr
10	//   pv24t -t -n 1000 <file.p24>  # Trace with instruction limit
11	
12	use pa24r::{Opcode, load_p24};
13	use std::io::{self, Read, Write};
14	use std::process;
15	
16	// 24-bit mask and sign extension
17	const MASK24: i32 = 0x00FF_FFFF;
18	
19	fn sign_extend_24(v: i32) -> i32 {
20	    let v = v & MASK24;
21	    if v & 0x0080_0000 != 0 {
22	        v | !MASK24 // sign-extend negative
23	    } else {
24	        v
25	    }
26	}
27	
28	fn wrap24(v: i32) -> i32 {
29	    sign_extend_24(v)
30	}
31	
32	// VM state
33	struct Vm {
34	    // Memory: code, data, globals, call stack, eval stack, heap — all in one flat array
35	    mem: Vec<u8>,
36	
37	    // Registers
38	    pc: usize,
39	    esp: usize,  // eval stack pointer (points to next free slot)
40	    csp: usize,  // call stack pointer (points to next free slot)
41	    fp_vm: usize, // frame pointer
42	    gp: usize,   // globals base
43	    hp: usize,   // heap pointer
44	
45	    // Layout boundaries
46	    code_size: usize,
47	    data_size: usize,
48	    global_count: usize,
49	    globals_base: usize,
50	    call_stack_base: usize,
51	    eval_stack_base: usize,
52	    heap_base: usize,
53	
54	    // Status
55	    status: u8, // 0=running, 1=halted, 2=trapped
56	    trap_code: u8,
57	
58	    // I/O
59	    stdin_buf: Vec<u8>,
60	    stdin_pos: usize,
61	
62	    // Trace
63	    trace: bool,
64	    instruction_count: u64,
65	    max_instructions: u64,
66	}
67	
68	const CALL_STACK_WORDS: usize = 256;
69	const EVAL_STACK_WORDS: usize = 256;
70	const HEAP_WORDS: usize = 256;
71	const WORD: usize = 3;
72	
73	impl Vm {
74	    fn new(image: pa24r::LoadedImage, stdin_data: Vec<u8>, trace: bool, max_instructions: u64) -> Self {
75	        let code_size = image.code.len();
76	        let data_size = image.data.len();
77	        let global_count = image.global_count as usize;
78	
79	        let globals_base = code_size + data_size;
80	        let globals_size = global_count * WORD;
81	        let call_stack_base = globals_base + globals_size;
82	        let call_stack_size = CALL_STACK_WORDS * WORD;
83	        let eval_stack_base = call_stack_base + call_stack_size;
84	        let eval_stack_size = EVAL_STACK_WORDS * WORD;
85	        let heap_base = eval_stack_base + eval_stack_size;
86	        let heap_size = HEAP_WORDS * WORD;
87	
88	        let total = heap_base + heap_size;
89	        let mut mem = vec![0u8; total];
90	
91	        // Load code
92	        mem[..code_size].copy_from_slice(&image.code);
93	        // Load data
94	        mem[code_size..code_size + data_size].copy_from_slice(&image.data);
95	
96	        Vm {
97	            mem,
98	            pc: image.entry_point as usize,
99	            esp: eval_stack_base,
100	            csp: call_stack_base,
101	            fp_vm: call_stack_base,
102	            gp: globals_base,
103	            hp: heap_base,
104	            code_size,
105	            data_size,
106	            global_count,
107	            globals_base,
108	            call_stack_base,
109	            eval_stack_base,
110	            heap_base,
111	            status: 0,
112	            trap_code: 0,
113	            stdin_buf: stdin_data,
114	            stdin_pos: 0,
115	            trace,
116	            instruction_count: 0,
117	            max_instructions,
118	        }
119	    }
120	
121	    // Memory access: 24-bit words stored little-endian in 3 bytes
122	    fn read_word(&self, addr: usize) -> i32 {
123	        if addr + 2 >= self.mem.len() {
124	            return 0;
125	        }
126	        let lo = self.mem[addr] as i32;
127	        let mid = self.mem[addr + 1] as i32;
128	        let hi = self.mem[addr + 2] as i32;
129	        sign_extend_24(lo | (mid << 8) | (hi << 16))
130	    }
131	
132	    fn write_word(&mut self, addr: usize, val: i32) {
133	        let v = val & MASK24;
134	        if addr + 2 >= self.mem.len() {
135	            self.trap(2); // stack overflow
136	            return;
137	        }
138	        self.mem[addr] = v as u8;
139	        self.mem[addr + 1] = (v >> 8) as u8;
140	        self.mem[addr + 2] = (v >> 16) as u8;
141	    }
142	
143	    fn read_byte(&self, addr: usize) -> i32 {
144	        if addr >= self.mem.len() { 0 } else { self.mem[addr] as i32 }
145	    }
146	
147	    fn write_byte(&mut self, addr: usize, val: i32) {
148	        if addr >= self.mem.len() {
149	            self.trap(2);
150	            return;
151	        }
152	        self.mem[addr] = val as u8;
153	    }
154	
155	    // Fetch operand bytes from code at pc
156	    fn fetch_u8(&mut self) -> u8 {
157	        let v = if self.pc < self.code_size { self.mem[self.pc] } else { 0 };
158	        self.pc += 1;
159	        v
160	    }
161	
162	    fn fetch_i8(&mut self) -> i32 {
163	        let v = self.fetch_u8() as i8;
164	        v as i32
165	    }
166	
167	    fn fetch_u24(&mut self) -> u32 {
168	        let lo = self.fetch_u8() as u32;
169	        let mid = self.fetch_u8() as u32;
170	        let hi = self.fetch_u8() as u32;
171	        lo | (mid << 8) | (hi << 16)
172	    }
173	
174	    // Eval stack operations
175	    fn push_eval(&mut self, val: i32) {
176	        if self.esp >= self.heap_base {
177	            self.trap(2); // stack overflow
178	            return;
179	        }
180	        self.write_word(self.esp, val);
181	        self.esp += WORD;
182	    }
183	
184	    fn pop_eval(&mut self) -> i32 {
185	        if self.esp <= self.eval_stack_base {
186	            self.trap(3); // stack underflow
187	            return 0;
188	        }
189	        self.esp -= WORD;
190	        self.read_word(self.esp)
191	    }
192	
193	    fn peek_eval(&self) -> i32 {
194	        if self.esp <= self.eval_stack_base { 0 }
195	        else { self.read_word(self.esp - WORD) }
196	    }
197	
198	    fn eval_depth(&self) -> usize {
199	        (self.esp - self.eval_stack_base) / WORD
200	    }
201	
202	    fn trap(&mut self, code: u8) {
203	        self.status = 2;
204	        self.trap_code = code;
205	    }
206	
207	    fn run(&mut self) {
208	        while self.status == 0 {
209	            if self.max_instructions > 0 && self.instruction_count >= self.max_instructions {
210	                eprintln!("pv24t: instruction limit reached ({} instructions)", self.max_instructions);
211	                self.status = 1;
212	                break;
213	            }
214	
215	            let instr_pc = self.pc;
216	            let op_byte = self.fetch_u8();
217	
218	            let op = match op_byte {
219	                0x00 => Opcode::Halt,
220	                0x01 => Opcode::Push,
221	                0x02 => Opcode::PushS,
222	                0x03 => Opcode::Dup,
223	                0x04 => Opcode::Drop,
224	                0x05 => Opcode::Swap,
225	                0x06 => Opcode::Over,
226	                0x10 => Opcode::Add,
227	                0x11 => Opcode::Sub,
228	                0x12 => Opcode::Mul,
229	                0x13 => Opcode::Div,
230	                0x14 => Opcode::Mod,
231	                0x15 => Opcode::Neg,
232	                0x16 => Opcode::And,
233	                0x17 => Opcode::Or,
234	                0x18 => Opcode::Xor,
235	                0x19 => Opcode::Not,
236	                0x1A => Opcode::Shl,
237	                0x1B => Opcode::Shr,
238	                0x20 => Opcode::Eq,
239	                0x21 => Opcode::Ne,
240	                0x22 => Opcode::Lt,
241	                0x23 => Opcode::Le,
242	                0x24 => Opcode::Gt,
243	                0x25 => Opcode::Ge,
244	                0x30 => Opcode::Jmp,
245	                0x31 => Opcode::Jz,
246	                0x32 => Opcode::Jnz,
247	                0x33 => Opcode::Call,
248	                0x34 => Opcode::Ret,
249	                0x35 => Opcode::Calln,
250	                0x36 => Opcode::Trap,
251	                0x40 => Opcode::Enter,
252	                0x41 => Opcode::Leave,
253	                0x42 => Opcode::Loadl,
254	                0x43 => Opcode::Storel,
255	                0x44 => Opcode::Loadg,
256	                0x45 => Opcode::Storeg,
257	                0x46 => Opcode::Addrl,
258	                0x47 => Opcode::Addrg,
259	                0x48 => Opcode::Loada,
260	                0x49 => Opcode::Storea,
261	                0x4A => Opcode::Loadn,
262	                0x4B => Opcode::Storen,
263	                0x50 => Opcode::Load,
264	                0x51 => Opcode::Store,
265	                0x52 => Opcode::Loadb,
266	                0x53 => Opcode::Storeb,
267	                0x60 => Opcode::Sys,
268	                _ => {
269	                    self.trap(4); // invalid opcode
270	                    continue;
271	                }
272	            };
273	
274	            // Trace: log before execution
275	            if self.trace {
276	                self.trace_instruction(instr_pc, op);
277	            }
278	
279	            self.execute(op);
280	            self.instruction_count += 1;
281	        }
282	
283	        // Print trap message (matches pvm.s behavior)
284	        if self.status == 2 {
285	            let stdout = io::stdout();
286	            let mut out = stdout.lock();
287	            let _ = write!(out, "TRAP {}\n", self.trap_code);
288	        }
289	    }
290	
291	    fn trace_instruction(&self, pc: usize, op: Opcode) {
292	        let stderr = io::stderr();
293	        let mut err = stderr.lock();
294	
295	        // Format: PC=XXXX OP=name [operands] | ESP=depth [top values] | FP=XXXX CSP=XXXX
296	        let _ = write!(err, "#{:<8} PC={:04X} ", self.instruction_count, pc);
297	
298	        // Decode operands for display (peek ahead without advancing pc)
299	        let code = &self.mem[..self.code_size];
300	        let next = self.pc; // pc already advanced past opcode
301	
302	        match op {
303	            // No operand
304	            Opcode::Halt | Opcode::Dup | Opcode::Drop | Opcode::Swap | Opcode::Over |
305	            Opcode::Add | Opcode::Sub | Opcode::Mul | Opcode::Div | Opcode::Mod | Opcode::Neg |
306	            Opcode::And | Opcode::Or | Opcode::Xor | Opcode::Not | Opcode::Shl | Opcode::Shr |
307	            Opcode::Eq | Opcode::Ne | Opcode::Lt | Opcode::Le | Opcode::Gt | Opcode::Ge |
308	            Opcode::Leave | Opcode::Load | Opcode::Store | Opcode::Loadb | Opcode::Storeb => {
309	                let _ = write!(err, "{:6}", format!("{op:?}").to_lowercase());
310	            }
311	            // Imm8
312	            Opcode::PushS | Opcode::Ret | Opcode::Trap | Opcode::Enter |
313	            Opcode::Loadl | Opcode::Storel | Opcode::Addrl |
314	            Opcode::Loada | Opcode::Storea | Opcode::Sys => {
315	                let imm = if next < code.len() { code[next] } else { 0 };
316	                let _ = write!(err, "{:6} {}", format!("{op:?}").to_lowercase(), imm);
317	            }
318	            // Imm24
319	            Opcode::Push | Opcode::Jmp | Opcode::Jz | Opcode::Jnz | Opcode::Call |
320	            Opcode::Loadg | Opcode::Storeg | Opcode::Addrg => {
321	                let imm = if next + 2 < code.len() {
322	                    code[next] as u32 | ((code[next+1] as u32) << 8) | ((code[next+2] as u32) << 16)
323	                } else { 0 };
324	                let _ = write!(err, "{:6} 0x{:06X}", format!("{op:?}").to_lowercase(), imm);
325	            }
326	            // D8A24
327	            Opcode::Calln => {
328	                let d = if next < code.len() { code[next] } else { 0 };
329	                let a = if next + 3 < code.len() {
330	                    code[next+1] as u32 | ((code[next+2] as u32) << 8) | ((code[next+3] as u32) << 16)
331	                } else { 0 };
332	                let _ = write!(err, "{:6} {} 0x{:06X}", "calln", d, a);
333	            }
334	            // D8O8
335	            Opcode::Loadn | Opcode::Storen => {
336	                let d = if next < code.len() { code[next] } else { 0 };
337	                let o = if next + 1 < code.len() { code[next + 1] } else { 0 };
338	                let _ = write!(err, "{:6} {} {}", format!("{op:?}").to_lowercase(), d, o);
339	            }
340	        }
341	
342	        // Stack state: show depth and top 4 values
343	        let depth = self.eval_depth();
344	        let _ = write!(err, " | ESP={}", depth);
345	        if depth > 0 {
346	            let _ = write!(err, " [");
347	            let show = depth.min(4);
348	            for i in 0..show {
349	                let addr = self.esp - (i + 1) * WORD;
350	                let val = self.read_word(addr);
351	                if i > 0 { let _ = write!(err, ", "); }
352	                let _ = write!(err, "{}", val);
353	            }
354	            if depth > 4 { let _ = write!(err, ", ..."); }
355	            let _ = write!(err, "]");
356	        }
357	
358	        let _ = write!(err, " | FP={:04X}", self.fp_vm);
359	        let _ = writeln!(err);
360	    }
361	
362	    fn execute(&mut self, op: Opcode) {
363	        match op {
364	            Opcode::Halt => {
365	                self.status = 1;
366	            }
367	
368	            Opcode::Push => {
369	                let val = self.fetch_u24() as i32;
370	                self.push_eval(sign_extend_24(val));
371	            }
372	
373	            Opcode::PushS => {
374	                let val = self.fetch_i8();
375	                self.push_eval(wrap24(val));
376	            }
377	
378	            Opcode::Dup => {
379	                let v = self.peek_eval();
380	                self.push_eval(v);
381	            }
382	
383	            Opcode::Drop => {
384	                self.pop_eval();
385	            }
386	
387	            Opcode::Swap => {
388	                let b = self.pop_eval();
389	                let a = self.pop_eval();
390	                self.push_eval(b);
391	                self.push_eval(a);
392	            }
393	
394	            Opcode::Over => {
395	                let b = self.pop_eval();
396	                let a = self.pop_eval();
397	                self.push_eval(a);
398	                self.push_eval(b);
399	                self.push_eval(a);
400	            }
401	
402	            // Arithmetic
403	            Opcode::Add => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a.wrapping_add(b))); }
404	            Opcode::Sub => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a.wrapping_sub(b))); }
405	            Opcode::Mul => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a.wrapping_mul(b))); }
406	            Opcode::Div => {
407	                let b = self.pop_eval();
408	                let a = self.pop_eval();
409	                if b == 0 { self.trap(1); return; }
410	                self.push_eval(wrap24(a / b));
411	            }
412	            Opcode::Mod => {
413	                let b = self.pop_eval();
414	                let a = self.pop_eval();
415	                if b == 0 { self.trap(1); return; }
416	                self.push_eval(wrap24(a % b));
417	            }
418	            Opcode::Neg => {
419	                let a = self.pop_eval();
420	                self.push_eval(wrap24(-a));
421	            }
422	
423	            // Logic
424	            Opcode::And => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a & b)); }
425	            Opcode::Or  => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a | b)); }
426	            Opcode::Xor => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a ^ b)); }
427	            Opcode::Not => { let a = self.pop_eval(); self.push_eval(wrap24(!a)); }
428	            Opcode::Shl => { let n = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a << (n & 0x1F))); }
429	            Opcode::Shr => { let n = self.pop_eval(); let a = self.pop_eval(); self.push_eval(wrap24(a >> (n & 0x1F))); }
430	
431	            // Comparison
432	            Opcode::Eq => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a == b { 1 } else { 0 }); }
433	            Opcode::Ne => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a != b { 1 } else { 0 }); }
434	            Opcode::Lt => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a < b { 1 } else { 0 }); }
435	            Opcode::Le => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a <= b { 1 } else { 0 }); }
436	            Opcode::Gt => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a > b { 1 } else { 0 }); }
437	            Opcode::Ge => { let b = self.pop_eval(); let a = self.pop_eval(); self.push_eval(if a >= b { 1 } else { 0 }); }
438	
439	            // Control flow
440	            Opcode::Jmp => {
441	                let addr = self.fetch_u24() as usize;
442	                self.pc = addr;
443	            }
444	
445	            Opcode::Jz => {
446	                let addr = self.fetch_u24() as usize;
447	                let flag = self.pop_eval();
448	                if flag == 0 { self.pc = addr; }
449	            }
450	
451	            Opcode::Jnz => {
452	                let addr = self.fetch_u24() as usize;
453	                let flag = self.pop_eval();
454	                if flag != 0 { self.pc = addr; }
455	            }
456	
457	            Opcode::Call => {
458	                let addr = self.fetch_u24() as usize;
459	                // Push frame header on call stack:
460	                //   [0] return PC
461	                //   [3] dynamic link (old fp_vm)
462	                //   [6] static link (= dynamic link for non-nested)
463	                //   [9] saved esp
464	                self.write_word(self.csp, self.pc as i32);        // return PC
465	                self.write_word(self.csp + WORD, self.fp_vm as i32);  // dynamic link
466	                self.write_word(self.csp + 2 * WORD, self.fp_vm as i32); // static link (same as dynamic for flat calls)
467	                self.write_word(self.csp + 3 * WORD, self.esp as i32);   // saved esp
468	                self.csp += 4 * WORD;
469	                self.pc = addr;
470	            }
471	
472	            Opcode::Calln => {
473	                let depth = self.fetch_u8();
474	                let addr = self.fetch_u24() as usize;
475	
476	                // Walk static link chain to find enclosing frame
477	                let mut sl = self.fp_vm;
478	                for _ in 0..depth {
479	                    sl = self.read_word(sl + 2 * WORD) as usize; // follow static links
480	                }
481	
482	                self.write_word(self.csp, self.pc as i32);
483	                self.write_word(self.csp + WORD, self.fp_vm as i32);
484	                self.write_word(self.csp + 2 * WORD, sl as i32); // static link from chain
485	                self.write_word(self.csp + 3 * WORD, self.esp as i32);
486	                self.csp += 4 * WORD;
487	                self.pc = addr;
488	            }
489	
490	            Opcode::Ret => {
491	                let nargs = self.fetch_u8() as usize;
492	
493	                // Restore from frame header at fp_vm
494	                let return_pc = self.read_word(self.fp_vm) as usize;
495	                let dynamic_link = self.read_word(self.fp_vm + WORD) as usize;
496	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
497	
498	                // Check if there's a return value on the eval stack
499	                // (function result sits above what was saved)
500	                let has_return = self.esp > self.read_word(self.fp_vm + 3 * WORD) as usize;
501	                let return_val = if has_return { Some(self.pop_eval()) } else { None };
502	
503	                // Restore state
504	                self.csp = self.fp_vm;
505	                self.fp_vm = dynamic_link;
506	                self.esp = saved_esp - nargs * WORD; // clean args
507	
508	                // Push return value if present
509	                if let Some(rv) = return_val {
510	                    self.push_eval(rv);
511	                }
512	
513	                self.pc = return_pc;
514	            }
515	
516	            Opcode::Trap => {
517	                let code = self.fetch_u8();
518	                self.trap(code);
519	            }
520	
521	            // Frame management
522	            Opcode::Enter => {
523	                let nlocals = self.fetch_u8() as usize;
524	                self.fp_vm = self.csp - 4 * WORD; // point to frame header
525	                // Allocate locals on call stack
526	                for _ in 0..nlocals {
527	                    self.write_word(self.csp, 0);
528	                    self.csp += WORD;
529	                }
530	            }
531	
532	            Opcode::Leave => {
533	                self.csp = self.fp_vm + 4 * WORD; // deallocate locals, keep frame header
534	            }
535	
536	            // Local variable access: offset from fp_vm + 4*WORD (past frame header)
537	            Opcode::Loadl => {
538	                let off = self.fetch_u8() as usize;
539	                let addr = self.fp_vm + 4 * WORD + off * WORD;
540	                let val = self.read_word(addr);
541	                self.push_eval(val);
542	            }
543	
544	            Opcode::Storel => {
545	                let off = self.fetch_u8() as usize;
546	                let val = self.pop_eval();
547	                let addr = self.fp_vm + 4 * WORD + off * WORD;
548	                self.write_word(addr, val);
549	            }
550	
551	            Opcode::Addrl => {
552	                let off = self.fetch_u8() as usize;
553	                let addr = self.fp_vm + 4 * WORD + off * WORD;
554	                self.push_eval(addr as i32);
555	            }
556	
557	            // Global variable access: offset from gp
558	            Opcode::Loadg => {
559	                let off = self.fetch_u24() as usize;
560	                let addr = self.gp + off * WORD;
561	                let val = self.read_word(addr);
562	                self.push_eval(val);
563	            }
564	
565	            Opcode::Storeg => {
566	                let off = self.fetch_u24() as usize;
567	                let val = self.pop_eval();
568	                let addr = self.gp + off * WORD;
569	                self.write_word(addr, val);
570	            }
571	
572	            Opcode::Addrg => {
573	                let off = self.fetch_u24() as usize;
574	                let addr = self.gp + off * WORD;
575	                self.push_eval(addr as i32);
576	            }
577	
578	            // Argument access: relative to saved_esp in frame
579	            Opcode::Loada => {
580	                let idx = self.fetch_u8() as usize;
581	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
582	                let addr = saved_esp - (idx + 1) * WORD;
583	                let val = self.read_word(addr);
584	                self.push_eval(val);
585	            }
586	
587	            Opcode::Storea => {
588	                let idx = self.fetch_u8() as usize;
589	                let val = self.pop_eval();
590	                let saved_esp = self.read_word(self.fp_vm + 3 * WORD) as usize;
591	                let addr = saved_esp - (idx + 1) * WORD;
592	                self.write_word(addr, val);
593	            }
594	
595	            // Nonlocal access via static link chain
596	            Opcode::Loadn => {
597	                let depth = self.fetch_u8() as usize;
598	                let off = self.fetch_u8() as usize;
599	                let frame = self.follow_static_links(depth);
600	                let addr = frame + 4 * WORD + off * WORD;
601	                let val = self.read_word(addr);
602	                self.push_eval(val);
603	            }
604	
605	            Opcode::Storen => {
606	                let depth = self.fetch_u8() as usize;
607	                let off = self.fetch_u8() as usize;
608	                let val = self.pop_eval();
609	                let frame = self.follow_static_links(depth);
610	                let addr = frame + 4 * WORD + off * WORD;
611	                self.write_word(addr, val);
612	            }
613	
614	            // Indirect memory access
615	            Opcode::Load => {
616	                let addr = self.pop_eval();
617	                if addr == 0 { self.trap(6); return; } // nil pointer
618	                let val = self.read_word(addr as usize);
619	                self.push_eval(val);
620	            }
621	
622	            Opcode::Store => {
623	                let addr = self.pop_eval();
624	                let val = self.pop_eval();
625	                if addr == 0 { self.trap(6); return; }
626	                self.write_word(addr as usize, val);
627	            }
628	
629	            Opcode::Loadb => {
630	                let addr = self.pop_eval();
631	                if addr == 0 { self.trap(6); return; }
632	                let val = self.read_byte(addr as usize);
633	                self.push_eval(val);
634	            }
635	
636	            Opcode::Storeb => {
637	                let addr = self.pop_eval();
638	                let val = self.pop_eval();
639	                if addr == 0 { self.trap(6); return; }
640	                self.write_byte(addr as usize, val);
641	            }
642	
643	            // System calls
644	            Opcode::Sys => {
645	                let id = self.fetch_u8();
646	                self.sys_call(id);
647	            }
648	        }
649	    }
650	
651	    fn follow_static_links(&self, depth: usize) -> usize {
652	        let mut frame = self.fp_vm;
653	        for _ in 0..depth {
654	            frame = self.read_word(frame + 2 * WORD) as usize;
655	        }
656	        frame
657	    }
658	
659	    fn sys_call(&mut self, id: u8) {
660	        match id {
661	            0 => {
662	                // HALT
663	                self.status = 1;
664	            }
665	            1 => {
666	                // PUTC
667	                let ch = self.pop_eval() as u8;
668	                let stdout = io::stdout();
669	                let mut out = stdout.lock();
670	                let _ = out.write_all(&[ch]);
671	                let _ = out.flush();
672	            }
673	            2 => {
674	                // GETC
675	                let ch = if self.stdin_pos < self.stdin_buf.len() {
676	                    let c = self.stdin_buf[self.stdin_pos];
677	                    self.stdin_pos += 1;
678	                    c as i32
679	                } else {
680	                    // Read from actual stdin
681	                    let mut buf = [0u8; 1];
682	                    match io::stdin().read_exact(&mut buf) {
683	                        Ok(()) => buf[0] as i32,
684	                        Err(_) => -1, // EOF
685	                    }
686	                };
687	                self.push_eval(ch);
688	            }
689	            3 => {
690	                // LED (ignore in tracer)
691	                self.pop_eval();
692	            }
693	            4 => {
694	                // ALLOC — bump allocator
695	                let size = self.pop_eval() as usize;
696	                let ptr = self.hp;
697	                self.hp += size;
698	                // Extend memory if needed
699	                if self.hp > self.mem.len() {
700	                    self.mem.resize(self.hp, 0);
701	                }
702	                self.push_eval(ptr as i32);
703	            }
704	            5 => {
705	                // FREE — no-op
706	                self.pop_eval();
707	            }
708	            6 => {
709	                // READ_SWITCH (always 0 in tracer)
710	                self.push_eval(0);
711	            }
712	            _ => {
713	                eprintln!("pv24t: unknown sys call {id}");
714	                self.trap(4);
715	            }
716	        }
717	    }
718	}
719	
720	fn usage() -> ! {
721	    eprintln!("pv24t — P-code Trace Interpreter for COR24");
722	    eprintln!();
723	    eprintln!("Usage: pv24t [options] <file.p24>");
724	    eprintln!();
725	    eprintln!("Options:");
726	    eprintln!("  -t          Enable instruction-level tracing to stderr");
727	    eprintln!("  -n <count>  Maximum instructions to execute (0 = unlimited)");
728	    eprintln!("  -i <text>   Provide stdin input as a string");
729	    eprintln!("  -h          Show this help");
730	    process::exit(1);
731	}
732	
733	fn main() {
734	    let args: Vec<String> = std::env::args().collect();
735	    let mut trace = false;
736	    let mut max_instructions: u64 = 0;
737	    let mut input_file = None;
738	    let mut stdin_text = None;
739	
740	    let mut i = 1;
741	    while i < args.len() {
742	        match args[i].as_str() {
743	            "-t" => { trace = true; i += 1; }
744	            "-n" => {
745	                i += 1;
746	                max_instructions = args.get(i).and_then(|s| s.parse().ok()).unwrap_or(0);
747	                i += 1;
748	            }
749	            "-i" => {
750	                i += 1;
751	                stdin_text = args.get(i).map(|s| s.clone());
752	                i += 1;
753	            }
754	            "-h" | "--help" => usage(),
755	            arg if !arg.starts_with('-') => {
756	                input_file = Some(arg.to_string());
757	                i += 1;
758	            }
759	            other => {
760	                eprintln!("pv24t: unknown option: {other}");
761	                usage();
762	            }
763	        }
764	    }
765	
766	    let path = match input_file {
767	        Some(p) => p,
768	        None => {
769	            eprintln!("pv24t: missing input file");
770	            usage();
771	        }
772	    };
773	
774	    let binary = match std::fs::read(&path) {
775	        Ok(b) => b,
776	        Err(e) => {
777	            eprintln!("pv24t: cannot read {path}: {e}");
778	            process::exit(1);
779	        }
780	    };
781	
782	    let image = match load_p24(&binary) {
783	        Ok(img) => img,
784	        Err(e) => {
785	            eprintln!("pv24t: {path}: {e}");
786	            process::exit(1);
787	        }
788	    };
789	
790	    if trace {
791	        eprintln!("pv24t: loaded {path}: code={} data={} globals={} entry=0x{:04X}",
792	            image.code.len(), image.data.len(), image.global_count, image.entry_point);
793	    }
794	
795	    let stdin_data = stdin_text.map(|s| s.into_bytes()).unwrap_or_default();
796	    let mut vm = Vm::new(image, stdin_data, trace, max_instructions);
797	    vm.run();
798	
799	    if trace {
800	        eprintln!("pv24t: {} instructions executed, status={}", vm.instruction_count, vm.status);
801	    }
802	
803	    process::exit(if vm.status == 2 { vm.trap_code as i32 } else { 0 });
804	}
