            0x22 => Some(Opcode::Lt),
            0x23 => Some(Opcode::Le),
            0x24 => Some(Opcode::Gt),
            0x25 => Some(Opcode::Ge),
            0x30 => Some(Opcode::Jmp),
            0x31 => Some(Opcode::Jz),
            0x32 => Some(Opcode::Jnz),
            0x33 => Some(Opcode::Call),
            0x34 => Some(Opcode::Ret),
            0x35 => Some(Opcode::Calln),
            0x36 => Some(Opcode::Trap),
            0x40 => Some(Opcode::Enter),
