            0x52 => Some(Opcode::Loadb),
            0x53 => Some(Opcode::Storeb),
            0x60 => Some(Opcode::Sys),
            _ => None,
        }
    }

    /// Mnemonic string for this opcode.
    pub const fn mnemonic(self) -> &'static str {
        match self {
            Opcode::Halt => "halt",
            Opcode::Push => "push",
            Opcode::PushS => "push_s",
            Opcode::Dup => "dup",
