            0x41,       // leave
            0x34, 0x00, // ret 0
            0x40, 0x03, // enter 3 (proc 1)
            0x41,       // leave
            0x34, 0x00, // ret 0
        ];
        let p24 = make_p24(0, code, &[], 0);
        let prog = decode_program(&p24).unwrap();

        assert_eq!(prog.procedures.len(), 2);
