    let has_jz = prog.instructions.iter().any(|i| i.op == Opcode::Jz);
    let has_jmp = prog.instructions.iter().any(|i| i.op == Opcode::Jmp);
    assert!(has_jz || has_jmp, "if_else.p24 should have branch instructions");

